-- ----------------------------
-- Table structure for `_robot`
-- ----------------------------
DROP TABLE IF EXISTS `_robot`;
CREATE TABLE `_robot` (
  `objId` int(10) NOT NULL DEFAULT '0',
  `name` varchar(20) NOT NULL DEFAULT '',
  `스폰_여부` enum('true','false') NOT NULL DEFAULT 'true',
  `행동` enum('사냥 & PvP','사냥','PvP','공성','공성 & PvP','허수아비 공격','낚시','마을 대기') NOT NULL DEFAULT '사냥 & PvP',
  `무기인챈트` tinyint(3) NOT NULL DEFAULT '0',
  `level` tinyint(3) NOT NULL DEFAULT '0',
  `exp` double DEFAULT '0',
  `ac` tinyint(3) NOT NULL DEFAULT '0',
  `mr` tinyint(3) NOT NULL DEFAULT '0',
  `sp` tinyint(3) NOT NULL DEFAULT '0',
  `str` tinyint(3) NOT NULL DEFAULT '0',
  `dex` tinyint(3) NOT NULL DEFAULT '0',
  `con` tinyint(3) NOT NULL DEFAULT '0',
  `wis` tinyint(3) NOT NULL DEFAULT '0',
  `inter` tinyint(3) NOT NULL DEFAULT '0',
  `cha` tinyint(3) NOT NULL DEFAULT '0',
  `class` enum('군주','기사','요정','마법사') NOT NULL DEFAULT '기사',
  `sex` enum('남자','여자') NOT NULL DEFAULT '남자',
  `clan_name` varchar(255) NOT NULL DEFAULT '',
  `clanID` mediumint(10) NOT NULL DEFAULT '0',
  `title` varchar(20) NOT NULL DEFAULT '',
  `lawful` int(10) NOT NULL DEFAULT '65536',
  `무기 이름` varchar(255) NOT NULL DEFAULT '',
  `마법 인형` varchar(255) NOT NULL DEFAULT '',
  `mythic_poly` enum('random','true','false') NOT NULL DEFAULT 'random',
  PRIMARY KEY (`objId`,`name`,`행동`) USING BTREE
) ENGINE=MyISAM DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC;

