-- Table structure for `_robot_book`
-- ----------------------------
DROP TABLE IF EXISTS `_robot_book`;
CREATE TABLE `_robot_book` (
  `location` varchar(100) NOT NULL DEFAULT '',
  `locX` int(10) unsigned NOT NULL DEFAULT '0',
  `locY` int(10) unsigned NOT NULL DEFAULT '0',
  `locMAP` int(10) unsigned NOT NULL DEFAULT '0',
  `입장레벨` int(10) NOT NULL DEFAULT '0',
  `enable` enum('true','false') DEFAULT 'true',
  PRIMARY KEY (`location`) USING BTREE,
  KEY `location` (`location`) USING BTREE
) ENGINE=MyISAM DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC;

