-- Table structure for `_robot_drop`
-- ----------------------------
DROP TABLE IF EXISTS `_robot_drop`;
CREATE TABLE `_robot_drop` (
  `class` enum('군주','기사','요정','마법사','다크엘프') NOT NULL DEFAULT '기사',
  `item_code` int(10) NOT NULL,
  `item_name` varchar(50) NOT NULL DEFAULT '',
  `item_bress` int(10) unsigned NOT NULL DEFAULT '0',
  `count_min` int(10) unsigned NOT NULL DEFAULT '1',
  `count_max` int(10) unsigned NOT NULL DEFAULT '1',
  `chance` int(10) NOT NULL DEFAULT '0',
  PRIMARY KEY (`class`,`item_code`,`item_name`,`item_bress`) USING BTREE
) ENGINE=MyISAM DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC;

