-- Table structure for `_robot_skill`
-- ----------------------------
DROP TABLE IF EXISTS `_robot_skill`;
CREATE TABLE `_robot_skill` (
  `class` enum('군주','기사','요정','마법사') NOT NULL DEFAULT '군주',
  `skill_uid` int(10) unsigned NOT NULL DEFAULT '0',
  `skill_name` varchar(50) NOT NULL DEFAULT '',
  `skill_type` enum('버프','디버프','단일공격마법','범위공격마법','힐','mp회복마법','서먼몬스터') NOT NULL DEFAULT '버프',
  `사용레벨` tinyint(3) NOT NULL DEFAULT '0',
  `시전확률` double(10,0) NOT NULL DEFAULT '100',
  `시전무기` enum('모든무기','한손검','양손검','한손검&양손검','활') NOT NULL DEFAULT '모든무기',
  `공격대상` enum('유저&몬스터','유저','몬스터') NOT NULL DEFAULT '유저&몬스터',
  `정령속성` enum('일반','물','바람','땅','불') NOT NULL DEFAULT '일반',
  PRIMARY KEY (`class`,`skill_uid`) USING BTREE,
  KEY `cha_objId` (`class`) USING BTREE,
  KEY `skill` (`skill_uid`) USING BTREE
) ENGINE=MyISAM DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC;

