INSERT INTO `_robot_clan_list` VALUES ('4', '플러스', '지은탁', '', '아줌마 신하균 김병만 권상우 박보영 이은결 송중기 우현 김래원 백성현 윤시윤 이동욱 이장우 곽한구 한지민 김현중 김길중 현영 원빈 구준표 강하늘 강민수 이지은 박현우 정하늘 송민호 최유리 김도영 한서연 박재민 이소라 오민재 정수현 김지우 박상혁 이가은 김영훈 오지민 정은주 박시영 한지우 최민정 이재원 김소희 유승호 정다은 송지혜 박지성 이영희 김상철 장민혁 윤지수 이보라 박도현 한솔이 송다영 박재영 유나은 이은솔 이찬호 박영수 한미래 최상민 이지혁 김상아 한상은 최다솜 박진수 이다은 최민수 이하늘 사람 연필 하늘 종이 소망 비밀 꿈틀 꽃잎 강물 바위 햇살 무지개 바구니 꽃병 조각 바람개비 카메라 탁자 의자 소파 장미 해바라기 민들레 나팔꽃 손수건 거울 화분 칠판 손톱 발톱 머리 눈물 눈동자 별자리 안개 나침반 비둘기 독수리 도마뱀 나비효과 바나나 딸기 사과 감자 은행나무 대나무 소나무 느티나무 쌀알 햇빛 우박 눈꽃 태양 달 별 목성 우주선 별똥별 천체 새벽별 저녁 낮 밤 검정 파랑 초록 분홍 고동 자주 카페 우유 젓가락 김하늘 지은탁 ');
INSERT INTO `_robot_clan_list` VALUES ('5', 'Z', '주원', '', '미륵 이승기 이현우 엠씨몽 주원 이종석 김창완 정일우 미달이 조진웅 박시후 이민기 이제훈 유아인 정우성 문근영 현빈 현아 윤아 티파니 정려원 장희빈 태진아 이루 김연아 박용규 공유 한가인 한예슬 구준엽 이지린 최지호 손예진 김태훈 유진아 이현정 조민수 정미래 이지영 박상민 김하늘 최정민 장수빈 이정수 윤상희 최지연 오현수 윤하늘 이은지 김종원 정우진 박하나 한상혁 최유빈 이주현 김소영 정민호 송가희 박찬호 이재희 김하연 오세훈 정민재 최석환 이시안 김태희 정승현 김유빈 정해리 오윤아 윤지영 김도희 정이안 송지훈 박소연 이정훈 정서연 오정우 윤미정 정희주 가위 나비 달빛 바다 바람 새벽 우주 별빛 나무 모래 구름 새소리 숲길 산책 돌멩이 해변 양초 그림자 유리 가방 책상 도서 빗방울 소나기 잔디 우산 신발 바지 책장 의류 단추 벽돌 손길 손잡이 무릎 웃음 전구 촛불 고양이 강아지 달팽이 꽃게 새우 복숭아 고구마 호박 무궁화 국화 버드나무 단풍 참나무 알밤 서리 산호 돌고래 바닷가재 화성 금성 은하수 행성 시간 시계 모래시계 정오 아침 점심 저녁노을 하얀 노랑 주황 보라 무지개색 커피 차 얼음 꽃다발 숟가락 ');
