INSERT INTO `_robot_skill` VALUES ('요정', '128', '네이쳐스 터치', '힐', '0', '100', '모든무기', '유저', '일반');
INSERT INTO `_robot_talk` VALUES ('1', '안녕]하이]ㅎㅇ', '안녕하세요, &님! 오늘 기분은 어때요?]&님 반가워요!]좋은 하루 되세요!');
INSERT INTO `_robot_talk` VALUES ('2', '뭐해]뭐하고있어]뭐함', '저는 지금 &님과 이야기 중이에요!]아무것도 안 하고 있었어요, &님]멍 때리고 있어요]저녁에 뭐 먹을지 생각 중이에요');
INSERT INTO `_robot_talk` VALUES ('3', '이름]너이름]너 이름이 뭐야]네이름', '제 이름은 $입니다!]&님의 친구, $예요!]저는 &님의 친구, $이에요!]$ 입니다!');
INSERT INTO `_robot_talk` VALUES ('4', '고마워]감사]땡큐', '저야말로 고마워요, &님!]언제든 도움이 필요하면 불러주세요!]감사합니다, &님!');
INSERT INTO `_robot_talk` VALUES ('5', '뭐할까]추천', '산책은 어떠세요?]맛있는 거 드시는 건 어때요?]책 읽기도 좋아요!]게임 한 판?');
INSERT INTO `_robot_talk` VALUES ('6', '심심해]지루해', '저랑 대화할까요?]노래 들어볼까요?]산책 추천해요!]퀴즈 내드릴까요?');
INSERT INTO `_robot_talk` VALUES ('7', '사랑해', '저도 &님을 정말 좋아해요!]사랑해요, &님!]고마워요, &님!]저는 &님을 응원합니다!');
INSERT INTO `_robot_talk` VALUES ('8', '잘자]굿나잇]잘자요]굿밤', '좋은 꿈 꾸세요, &님!]편안한 밤 되세요!]내일도 힘내요, &님!');
INSERT INTO `_robot_talk` VALUES ('9', '잘있어]잘잇어]', '&님도 건강하게 지내세요!]언제든 다시 불러주세요!]다음에 또 만나요!');
INSERT INTO `_robot_talk` VALUES ('10', '밥먹었어]식사했어]밥 먹었어', '아직이요! &님은요?]방금 먹었어요!]배고파요, &님은요?');
INSERT INTO `_robot_talk` VALUES ('11', '심심해', '재밌는 이야기 해드릴까요?]퀴즈 맞추기 해볼래요?]노래 추천해드릴까요?');
INSERT INTO `_robot_talk` VALUES ('12', '오늘날씨', '오늘 날씨가 정말 좋아요!]비가 올 것 같아요!]맑은 하루예요!]날씨가 흐려요!');
INSERT INTO `_robot_talk` VALUES ('13', '힘들어]피곤해', '많이 힘드셨군요. 잠시 쉬어가세요!]&님, 화이팅! 힘내세요!]저랑 이야기하면 기운 날 거예요!');
INSERT INTO `_robot_talk` VALUES ('14', '좋아하는음식]좋아하는 음식', '저는 피자를 제일 좋아해요!]치킨도 좋아해요!]요즘 라면에 빠졌어요!]&님은요?');
INSERT INTO `_robot_talk` VALUES ('15', '취미]취미뭐야', '독서가 취미예요!]영화 보는 걸 좋아해요!]음악 듣는 걸 즐겨요!');
INSERT INTO `_robot_talk` VALUES ('16', '놀자', '좋아요! 뭐 하고 놀까요?]게임할까요?]퀴즈 내드릴까요?');
INSERT INTO `_robot_talk` VALUES ('17', '웃겨줘]재밌는얘기', '아재개그 들어보실래요? “돼지가 좋아하는 음악은 뭘까요? 돼지쏭!”]재밌는 이야기 들려드릴까요?');
INSERT INTO `_robot_talk` VALUES ('18', '나 몇살 같아]내 나이', '음… 20대 초반 느낌이에요!]비밀로 할게요!]&님은 항상 젊어 보여요!');
INSERT INTO `_robot_talk` VALUES ('19', '잘했어]수고했어', '칭찬해 주셔서 감사합니다, &님!]&님도 고생 많으셨어요!]멋져요, &님!');
INSERT INTO `_robot_talk` VALUES ('20', '게임하자', '어떤 게임을 하고 싶으신가요?]고전게임도 좋아해요!]');
INSERT INTO `_robot_talk` VALUES ('21', '퀴즈]문제내줘', '좋아요! 첫 번째 문제: 대한민국의 수도는 어디일까요?]');
INSERT INTO `_robot_talk` VALUES ('22', '서울', '정답입니다, &님! 정말 똑똑하시네요!]');
INSERT INTO `_robot_talk` VALUES ('23', '배고파', '뭐라도 챙겨 드세요!]간단한 간식 추천드려요!]혹시 라면 좋아하세요?');
INSERT INTO `_robot_talk` VALUES ('24', '졸려', '잠시 눈을 붙이는 것도 좋아요!]스트레칭 하실래요?]커피 한 잔 어때요?');
